mapper.update:
update batch.batch_day_instance
set day_status = 'CUTOFF',
    cutoff_at = #{cutoffAt},
    updated_at = current_timestamp
where id = #{id}
  and tenant_id = #{tenantId}
  and calendar_code = #{calendarCode}
  and biz_date = #{bizDate}
  and day_status = 'OPEN'
  and cutoff_at is null
